<template>
<div class="cart">
  <!-- <div class="topSpace"></div> -->
  <div class="navCart">
    <div class="nav">
      <p>购物车({{cart_list.length}})</p> 
      <span @click="buttonshow=!buttonshow">{{buttonshow==true?"管理":"取消"}}</span>
    </div>
    <van-notice-bar left-icon="volume-o" mode="closeable">开通尊享VIP会员，享388个精选品牌全年折95折</van-notice-bar>

     </div>
 <div class="item" v-for="(item,index) in cart_list" :key="item.id">
    <div class="select-btn">
      <div class="checkbox-wrapper">
        <label class="well-check">
          <input class="checkbox" 
          type="checkbox" 
          @click="toggle(index)"
          ref="checkboxes"
          value="" />
        </label>
      </div>
    </div>
    <div class="content">
      <div class="left">
        <div class="pictrue">
          <img
            :src="item.productInfo.attrInfo.image"
          />
        </div>
      </div>
      <div class="right">
        <div class="text">
          <div class="line1">
            {{item.productInfo.store_name}}
          </div>
          <div class="infor">规格：{{item.productInfo.attrInfo.suk}}</div>
        </div>
        <div class="line2">
          <div class="money">￥{{item.productInfo.attrInfo.price}}</div>
          <div class="carnum">
          
            <van-stepper @plus="add(index)" @minus="subtra(index)" button-size="22" :v-model="num" min="1" max="10" integer />
          </div>
        </div>
      </div>
    </div>
  </div>
  <van-submit-bar :price="totalPrice*100" button-text="提交订单" @submit="onSubmit">
    <p> 
      <input ref="box2" type="checkbox" class="checkbox">
      <span> 已选 </span>
      </p>

  </van-submit-bar>
 
  </div>
</template>

<script>

export default {

  data(){return{
    cart_list:[],
    checked:true,
    buttonshow:true,
    totalPrice:0,
    id:'',
    checkedNum:0,
    num:0
  }},
 
  created(){
    this.axios.get('api/cart/list').then(d=>{
      this.cart_list = d.data.data.valid;
      console.log("购物车列表=>",this.cart_list);
    })
  },
  methods:{
      toggle(index){
            this.id=this.cart_list[index].id;
           
            if(this.$refs.checkboxes[index].checked){
                this.totalPrice+=this.cart_list[index].productInfo.attrInfo.price*this.cart_list[index].cart_num;
                this.$refs.box2.checked= this.checked;
                
            }else{
                
                this.totalPrice-=this.cart_list[index].productInfo.attrInfo.price*this.cart_list[index].cart_num;
            }
            
            console.log(this.totalPrice);
        },
    onSubmit(){
    
           this.$router.push({
                path: "/ConfirmDetail",
                query: {cId: this.id},
              });
            
  
    },
     add(i){
    this.num++;
    this.totalPrice = this.num*(this.item.productInfo.attrInfo.price);
    console.log("this.num=>",this.num,i);

  },
  subtra(i){
    this.num--;
    console.log("this.num=>",this.num,i);
  }

  }

}
</script>

